/** Log the current result's actual quoted/PO price so the model self-calibrates. */
function logActualQuote(): void {
  if (!lastResult) { showToast('Run Calculate first, then log the actual', 'warning'); return; }
  const raw = window.prompt(`Enter the ACTUAL quoted / PO unit price for "${lastResult.partName}" (${_displayCurrency}) — the model estimated ${_currFmt(lastResult.total)}:`);
  if (raw === null) return;
  const actual = parseFloat(raw.replace(/[^0-9.]/g, ''));
  if (!Number.isFinite(actual) || actual <= 0) { showToast('Please enter a positive number', 'warning'); return; }
  const recs = getCalibrationRecords();
  recs.push({
    id: Date.now().toString(36) + Math.random().toString(36).slice(2, 6),
    savedAt: Date.now(),
    commodity: activeCommodity,
    region: (document.getElementById('mfg-region-selector') as HTMLSelectElement)?.value ?? 'UK',
    shouldCost: lastResult.total,
    actualCost: actual,
    currency: _displayCurrency,
  });
  saveCalibrationRecords(recs);
  const s = computeCalibration(recs, activeCommodity);
  showToast(s.applied
    ? `Logged. ${activeCommodity.replace(/_/g, ' ')} now calibrated ×${s.biasFactor} from ${s.n} quotes (MAPE ${s.calibratedMapePct}%).`
    : `Logged (${s.n}/${3} quotes for ${activeCommodity.replace(/_/g, ' ')} — need ${3 - s.n} more to calibrate).`, 'info');
  if (lastResult && lastInput) renderInsights(lastResult, lastInput);
}

// ─── View switching ───────────────────────────────────────────────────────────


function showHome(): void {
  const homeEl = document.getElementById('home-view');
  const pickerEl = document.getElementById('commodity-picker-view');
  const costingEl = document.getElementById('costing-view');
  const backdrop = document.getElementById('picker-backdrop');
  const errEl = document.getElementById('validation-errors');
  const warnEl = document.getElementById('validation-warnings');
  document.body.classList.remove('cv-new-costing');
  document.body.classList.remove('sidebar-collapsed');
  document.getElementById('news-view')?.style.setProperty('display', 'none');
  if (homeEl) homeEl.style.display = '';
  if (pickerEl) pickerEl.style.display = 'none';
  if (backdrop) { backdrop.classList.remove('visible'); backdrop.style.display = 'none'; }
  if (costingEl) {
    costingEl.classList.remove('wf-panel', 'wf-panel--open');
    costingEl.style.display = 'none';
  }
  document.getElementById('wf-panel-header')?.style?.setProperty('display','none');
  if (errEl) errEl.style.display = 'none';
  if (warnEl) warnEl.style.display = 'none';
  showDashboardSkeleton();
  setTimeout(renderDashboard, 340);
}


function showCosting(commodity?: string): void {
  const homeEl = document.getElementById('home-view');
  const pickerEl = document.getElementById('commodity-picker-view');
  const costingEl = document.getElementById('costing-view');
  const backdrop = document.getElementById('picker-backdrop');
  document.body.classList.remove('cv-new-costing');
  document.body.classList.remove('sidebar-collapsed');
  document.getElementById('news-view')?.style.setProperty('display', 'none');
  if (homeEl) homeEl.style.display = 'none';
  if (pickerEl) pickerEl.style.display = 'none';
  if (backdrop) { backdrop.classList.remove('visible'); backdrop.style.display = 'none'; }
  if (costingEl) {
    costingEl.classList.remove('wf-panel', 'wf-panel--open');
    costingEl.style.display = '';
  }
  document.getElementById('wf-panel-header')?.style?.setProperty('display','none');
  if (commodity) switchCommodity(commodity as CommodityType);
  // Animate panels into view after form renders
  setTimeout(() => onViewShown('costing'), 60);
}

