function wireCADEvents(): void {
  const dropZone = el('cad-drop-zone');
  const fileInput = el<HTMLInputElement>('cad-file-input');
  const analyzeBtn = el('cad-analyze-btn');

  // File input change
  fileInput.addEventListener('change', () => {
    const f = fileInput.files?.[0];
    if (f) setCADFile(f);
  });

  // Drag-drop
  dropZone.addEventListener('dragover', e => { e.preventDefault(); dropZone.classList.add('dragover'); });
  dropZone.addEventListener('dragleave', () => dropZone.classList.remove('dragover'));
  dropZone.addEventListener('drop', e => {
    e.preventDefault();
    dropZone.classList.remove('dragover');
    const f = e.dataTransfer?.files?.[0];
    if (f) setCADFile(f);
  });
  dropZone.addEventListener('click', (e) => {
    if ((e.target as HTMLElement).tagName !== 'LABEL' && (e.target as HTMLElement).tagName !== 'INPUT')
      fileInput.click();
  });

  // Clear button
  el('cad-clear-btn')?.addEventListener('click', () => {
    cadFile = null; cadAnalysisResult = null; cadOCCTGeometry = null;
    document.getElementById('cad-file-info')?.style.setProperty('display', 'none');
    document.getElementById('cad-drop-zone')?.style.setProperty('display', '');
    analyzeBtn?.setAttribute('disabled', 'true');
    document.getElementById('cad-analyze-calc-btn')?.setAttribute('disabled', 'true');
    const cadRes = document.getElementById('cad-results');
    if (cadRes) cadRes.innerHTML = '';
  });

  // Commodity override → rebuild material dropdown
  const commSel = document.getElementById('cad-commodity-override') as HTMLSelectElement | null;
  const matSel  = document.getElementById('cad-material-override')  as HTMLSelectElement | null;
  if (commSel && matSel) {
    commSel.addEventListener('change', () => {
      matSel.innerHTML = _buildCadMaterialOptions(commSel.value);
    });
  }

  // Part photo
  const photoInput = document.getElementById('cad-photo-input') as HTMLInputElement | null;
  const photoInfo  = document.getElementById('cad-photo-info');
  const photoClear = document.getElementById('cad-photo-clear') as HTMLButtonElement | null;
  if (photoInput) {
    photoInput.addEventListener('change', () => {
      const f = photoInput.files?.[0];
      if (!f) return;
      const reader = new FileReader();
      reader.onload = (ev) => {
        const img = new Image();
        img.onload = () => {
          const maxDim = 1024;
          const scale = Math.min(1, maxDim / Math.max(img.width, img.height));
          const canvas = document.createElement('canvas');
          canvas.width = Math.round(img.width * scale);
          canvas.height = Math.round(img.height * scale);
          const ctx = canvas.getContext('2d')!;
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          cadPartPhotoBase64 = canvas.toDataURL('image/jpeg', 0.82).split(',')[1];
          cadPartPhotoMime = 'image/jpeg';
          if (photoInfo) photoInfo.textContent = `${f.name} (${canvas.width}×${canvas.height}px)`;
          if (photoClear) photoClear.style.display = '';
        };
        img.src = ev.target?.result as string;
      };
      reader.readAsDataURL(f);
    });
  }
  if (photoClear) {
    photoClear.addEventListener('click', () => {
      cadPartPhotoBase64 = '';
      if (photoInput) photoInput.value = '';
      if (photoInfo) photoInfo.textContent = 'No photo selected';
      photoClear.style.display = 'none';
    });
  }

  // Analyze button
  analyzeBtn.addEventListener('click', () => { void analyzeCAD(false); });
  el('cad-analyze-calc-btn')?.addEventListener('click', () => { void analyzeCAD(true); });
}

function setCADFile(f: File): void {
  const ext = f.name.toLowerCase().split('.').pop() ?? '';
  if (!['stp', 'step', 'igs', 'iges'].includes(ext)) {
    alert('Unsupported file format. Please use STEP (.stp/.step) or IGES (.igs/.iges).');
    return;
  }
  cadFile = f;
  document.getElementById('cad-drop-zone')?.style.setProperty('display', 'none');
  const cadFileInfo = document.getElementById('cad-file-info');
  if (cadFileInfo) cadFileInfo.style.display = 'flex';
  const cadFname = document.getElementById('cad-fname');
  if (cadFname) cadFname.textContent = f.name;
  const cadFsize = document.getElementById('cad-fsize');
  if (cadFsize) cadFsize.textContent = (f.size / 1024).toFixed(1) + ' KB';
  document.getElementById('cad-analyze-btn')?.removeAttribute('disabled');
  document.getElementById('cad-analyze-calc-btn')?.removeAttribute('disabled');
  const cadResults = document.getElementById('cad-results');
  if (cadResults) cadResults.innerHTML = '';
  cadAnalysisResult = null;
  cadOCCTGeometry = null;
}

async function analyzeCAD(autoCalculate = false): Promise<void> {
  if (!cadFile) return;

  const apiKey = val('cad-api-key');
  if (apiKey) sessionStorage.setItem('cad-api-key', apiKey);

  const progress = document.getElementById('cad-progress-wrap');
  const progressFill = document.getElementById('cad-progress-fill');
  const progressLabel = document.getElementById('cad-progress-label');
  const analyzeBtn = document.getElementById('cad-analyze-btn');
  const analyzeCalcBtn = document.getElementById('cad-analyze-calc-btn');

  if (!progress || !progressFill || !progressLabel || !analyzeBtn || !analyzeCalcBtn) return;

  const updateProgress = (pct: number, label: string) => {
    (progressFill as HTMLElement).style.width = pct + '%';
    progressLabel.textContent = label;
  };

  progress.style.display = '';
  analyzeBtn.setAttribute('disabled', 'true');
  analyzeCalcBtn.setAttribute('disabled', 'true');
  const cadResultsEl = document.getElementById('cad-results');
  if (cadResultsEl) cadResultsEl.innerHTML = '';

  const controller = new AbortController();
  const timeoutId = setTimeout(
    () => controller.abort(new DOMException('Analysis timed out after 150s', 'TimeoutError')),
    150_000,
  );

  try {
    updateProgress(10, 'Uploading file…');
    const formData = new FormData();
    formData.append('cadFile', cadFile);

    // User overrides
    const commOvr = (document.getElementById('cad-commodity-override') as HTMLSelectElement | null)?.value ?? '';
    const matOvr  = (document.getElementById('cad-material-override')  as HTMLSelectElement | null)?.value ?? '';
    const annVol  = (document.getElementById('cad-annual-volume') as HTMLInputElement | null)?.value ?? '100000';
    const ovrWt   = (document.getElementById('cad-ovr-weight')  as HTMLInputElement | null)?.value ?? '';
    const ovrVol  = (document.getElementById('cad-ovr-volume')  as HTMLInputElement | null)?.value ?? '';
    const ovrLen  = (document.getElementById('cad-ovr-length')  as HTMLInputElement | null)?.value ?? '';
    const ovrW    = (document.getElementById('cad-ovr-width')   as HTMLInputElement | null)?.value ?? '';
    const ovrH    = (document.getElementById('cad-ovr-height')  as HTMLInputElement | null)?.value ?? '';
    const ovrDens = (document.getElementById('cad-ovr-density') as HTMLInputElement | null)?.value ?? '';

    if (commOvr) formData.append('commodity', commOvr);
    if (matOvr)  formData.append('material', matOvr);
    formData.append('annualVolume', annVol || '100000');
    if (ovrWt)   formData.append('weightKg', ovrWt);
    if (ovrVol)  formData.append('volumeCm3', ovrVol);
    if (ovrLen)  formData.append('lengthMm', ovrLen);
    if (ovrW)    formData.append('widthMm', ovrW);
    if (ovrH)    formData.append('heightMm', ovrH);
    if (ovrDens) formData.append('densityGcm3', ovrDens);
    if (cadPartPhotoBase64) {
      formData.append('partPhotoBase64', cadPartPhotoBase64);
      formData.append('partPhotoMime', cadPartPhotoMime);
    }

    const headers: HeadersInit = {};
    if (apiKey) headers['x-api-key'] = apiKey;

    updateProgress(20, 'Running OCCT geometry engine…');
    const res = await fetch('/api/cad/analyze', {
      method: 'POST', headers, body: formData, signal: controller.signal,
    });

    updateProgress(85, 'AI feature analysis…');
    const data = await res.json() as {
      success?: boolean;
      analysis?: CADAnalysisResult;
      occtGeometry?: OCCTGeometry | null;
      geometrySource?: 'occt' | 'text_parsing';
      annualVolume?: number;
      error?: string;
    };

    if (!res.ok || !data.success) throw new Error(data.error ?? `Server error ${res.status}`);

    updateProgress(100, data.geometrySource === 'occt' ? 'OCCT complete — precise geometry extracted' : 'Complete (text-parsed)');
    cadAnalysisResult = data.analysis!;
    cadOCCTGeometry = data.occtGeometry ?? null;
    cadGeometrySource = data.geometrySource ?? 'text_parsing';

    const partNameEl = el<HTMLInputElement>('part-name');
    if (partNameEl && cadAnalysisResult.partName) partNameEl.value = cadAnalysisResult.partName;

    el('export-all-pdf-btn').style.display = '';
    setTimeout(() => { progress.style.display = 'none'; }, 600);
    const resolvedAnnualVol = data.annualVolume ?? (parseFloat(annVol) || 100000);
    renderCADResults(cadAnalysisResult, autoCalculate, resolvedAnnualVol);
  } catch (err) {
    progress.style.display = 'none';
    const cadErrEl = document.getElementById('cad-results');
    if (cadErrEl) cadErrEl.innerHTML = `
      <div class="risk-card High" style="margin-top:10px">
        <div class="risk-feature">Analysis Error</div>
        <div>${escHtml(err instanceof Error ? err.message : String(err))}</div>
        <div class="risk-suggestion">Ensure the API server is running (<code>npm run server</code>) and ANTHROPIC_API_KEY is configured.</div>
      </div>`;
  } finally {
    clearTimeout(timeoutId);
    analyzeBtn?.removeAttribute('disabled');
    analyzeCalcBtn?.removeAttribute('disabled');
  }
}

/**
 * #3 Feature-based costing card — turns OCCT feature recognition (holes, threads,
 * planar vs free-form faces, undercuts, setups) into a per-feature cost breakdown
 * + DFM, so the designer sees exactly which features drive machining cost.
 */
function buildFeatureCostCard(): string {
  const f = cadOCCTGeometry?.features;
  if (!f || (f.estimatedHoleCount + f.planarFaceCount + f.freeFormFaceCount) === 0) return '';
  const undercuts = cadOCCTGeometry?.draftAnalysis?.undercutFaceCount ?? 0;
  const setups = cadOCCTGeometry?.setupAnalysis?.estimatedSetupCount ?? 1;
  const threadCount = f.threadFeaturesDetected ? Math.max(1, Math.round(f.estimatedHoleCount * 0.3)) : 0;
  // Material factor from the AI-suggested material (harder alloys machine slower).
  const matStr = `${cadAnalysisResult?.costInputSuggestions?.materialId ?? ''}`.toLowerCase();
  const matFactor = /ti|titan/.test(matStr) ? 2.5 : /inconel|nickel|superalloy/.test(matStr) ? 3.0
    : /steel|stainless|iron/.test(matStr) ? 1.5 : /alum/.test(matStr) ? 1.0 : 1.2;

  const fc = computeFeatureCosting({
    holeCount: f.estimatedHoleCount, holeRadiiMm: f.holeRadiiMm ?? [],
    threadCount, planarFaceCount: f.planarFaceCount, freeFormFaceCount: f.freeFormFaceCount,
    undercutFaceCount: undercuts, setupCount: setups,
  }, { materialFactor: matFactor });

  const rows = fc.lines.map(l => `
    <tr>
      <td style="padding:3px 8px">${escHtml(l.feature)}</td>
      <td style="padding:3px 8px;text-align:right">${l.count}</td>
      <td style="padding:3px 8px;text-align:right">${l.totalMinutes} min</td>
      <td style="padding:3px 8px;text-align:right;font-weight:600">${_currFmt(l.costGBP)}</td>
      <td style="padding:3px 8px;text-align:right;color:var(--text-muted)">${l.pctOfCost}%</td>
    </tr>`).join('');
  const dfm = fc.dfm.map(d => `<div style="font-size:0.72rem;color:${d.severity === 'major' ? 'var(--amber, #d97706)' : 'var(--text-secondary)'};margin-top:3px">• ${escHtml(d.title)} — ${escHtml(d.recommendation)}</div>`).join('');

  return `
    <div style="margin-bottom:12px;border:1px solid var(--border);border-left:4px solid #0891b2;border-radius:8px;padding:10px 12px;background:var(--surface-elevated)">
      <div style="display:flex;justify-content:space-between;align-items:baseline;flex-wrap:wrap;gap:8px">
        <div class="panel-title" style="margin:0">🧩 Feature-based cost breakdown <span style="font-weight:400;font-size:0.72rem;color:var(--text-muted)">(from CAD geometry)</span></div>
        <div style="font-size:0.95rem;font-weight:700;color:#0891b2">${_currFmt(fc.machiningCostGBP)} <span style="font-size:0.72rem;color:var(--text-muted)">· ${fc.totalCycleMin} min</span></div>
      </div>
      <table style="width:100%;border-collapse:collapse;font-size:0.76rem;margin-top:8px">
        <tr style="color:var(--text-muted);text-align:left"><th style="padding:2px 8px;font-weight:600">Feature</th><th style="padding:2px 8px;text-align:right">Count</th><th style="padding:2px 8px;text-align:right">Time</th><th style="padding:2px 8px;text-align:right">Cost</th><th style="padding:2px 8px;text-align:right">%</th></tr>
        ${rows}
      </table>
      <div style="margin-top:6px;font-size:0.72rem;color:var(--text-secondary)">Cost driver: <strong>${escHtml(fc.costliestFeature)}</strong></div>
      ${dfm ? `<div style="margin-top:6px;border-top:1px solid var(--border);padding-top:5px">${dfm}</div>` : ''}
    </div>`;
}

function renderCADResults(r: CADAnalysisResult, autoCalculate = false, annualVolume = 100000): void {
  const panel = el('cad-results');
  if (!panel) return;   // CAD results container not in the DOM for this view — avoid null.innerHTML crash
  const g = r.geometry;

  // Confidence badge helper — looks up AI-provided per-field confidence scores
  const fc = (r.costInputSuggestions as CADAnalysisResult['costInputSuggestions'] & { fieldConfidences?: Record<string, number> }).fieldConfidences ?? {};
  const confBadge = (key: string, ...fallbacks: string[]): string => {
    for (const k of [key, ...fallbacks]) {
      if (fc[k] !== undefined) {
        const v = fc[k];
        const pct = Math.round(v * 100);
        const cls = v >= 0.8 ? 'High' : v >= 0.5 ? 'Medium' : 'Low';
        return `<span class="cad-confidence-badge ${cls}" style="font-size:0.62rem;padding:1px 5px;margin-left:4px;vertical-align:middle">${pct}%</span>`;
      }
    }
    return '';
  };
  const bb = g.boundingBoxMm;
  const scoreClass = r.manufacturabilityScore >= 75 ? 'score-high' : r.manufacturabilityScore >= 50 ? 'score-med' : 'score-low';

  const recommendedCommodity = r.costInputSuggestions.recommendedCommodity as CommodityType;
  const commodityLabel: Record<string, string> = {
    machining: 'Machining', sheet_metal: 'Sheet Metal', sheet_metal_fab: 'SM Fab',
    injection_moulding: 'Injection Moulding', casting: 'Casting', forging: 'Forging',
    cast_and_machine: 'Cast+Machine', rubber: 'Rubber', composites: 'Composites',
    blow_moulding: 'Blow Moulding', thermoforming: 'Thermoforming',
    rotational_moulding: 'Rotomoulding', wiring_harness: 'Harness',
    extrusion: 'Extrusion', pcb_fab: 'PCB Fab', pcba: 'PCBA',
    biw_assembly: 'BIW Assembly', painting: 'Painting', assembly: 'Assembly',
  };

  // Build OCCT geometry panel HTML
  const occtPanel = buildOCCTPanel(cadOCCTGeometry, cadGeometrySource);

  panel.innerHTML = `
    <!-- Header summary -->
    <div style="display:flex;align-items:center;gap:16px;padding:12px 0;border-bottom:1px solid var(--border);margin-bottom:12px">
      <div style="text-align:center">
        <div class="cad-score-ring ${scoreClass}">${r.manufacturabilityScore}</div>
        <div style="font-size:0.7rem;color:var(--text-muted)">Manufacturability</div>
      </div>
      <div style="flex:1">
        <div style="font-weight:700;font-size:0.9rem">${escHtml(r.partName)}</div>
        <div style="font-size:0.78rem;color:var(--text-secondary);margin-top:2px">
          ${bb.x.toFixed(0)}×${bb.y.toFixed(0)}×${bb.z.toFixed(0)} mm &nbsp;·&nbsp;
          ${g.estimatedVolumeCm3.toFixed(1)} cm³ &nbsp;·&nbsp;
          ${g.estimatedWeightKg.aluminum.toFixed(3)} kg Al / ${g.estimatedWeightKg.steel.toFixed(3)} kg Steel
        </div>
        <div style="margin-top:4px">
          <span class="cad-confidence-badge ${r.confidenceLevel}">AI: ${r.confidenceLevel}</span>
          &nbsp;
          <span class="occt-source-badge ${cadGeometrySource === 'occt' ? 'occt' : 'text'}">${cadGeometrySource === 'occt' ? 'OCCT Kernel' : 'Text-parsed'}</span>
          &nbsp;
          <span style="font-size:0.72rem;color:var(--text-muted)">${g.estimatedSurfaceAreaCm2.toFixed(0)} cm² surface</span>
          ${r.costInputSuggestions.stage1Selection ? `&nbsp;<span style="font-size:0.68rem;background:var(--border);border-radius:3px;padding:1px 5px;color:var(--text-muted)" title="Stage 1 Haiku pre-selection">⚡ ${escHtml(r.costInputSuggestions.stage1Selection.primary)} (${Math.round((r.costInputSuggestions.stage1Selection.conf ?? 0) * 100)}%)</span>` : ''}
        </div>
      </div>
    </div>

    ${occtPanel}

    ${buildFeatureCostCard()}

    <!-- Detected features -->
    <div style="margin-bottom:12px">
      <div class="panel-title" style="margin-bottom:6px">Detected Features</div>
      <div>
        ${r.detectedFeatures.map(f =>
          `<span class="feature-badge ${f.significance}" title="${escHtml(f.description)}">${escHtml(f.type)}${f.count > 1 ? ' ×' + f.count : ''}</span>`
        ).join('')}
      </div>
    </div>

    <!-- Material suggestion -->
    <div style="margin-bottom:12px">
      <div class="panel-title" style="margin-bottom:6px">Material Analysis</div>
      <div style="font-size:0.8rem">
        <strong>${escHtml(r.materialAnalysis.primarySuggestion.name)}</strong>
        <span class="cad-confidence-badge ${r.materialAnalysis.primarySuggestion.confidencePct >= 75 ? 'High' : r.materialAnalysis.primarySuggestion.confidencePct >= 50 ? 'Medium' : 'Low'}"
              style="margin-left:6px">${r.materialAnalysis.primarySuggestion.confidencePct}%</span>
        ${r.materialAnalysis.fromMetadata ? '<span style="font-size:0.7rem;color:var(--green);margin-left:6px">✓ from CAD metadata</span>' : ''}
        <div style="color:var(--text-secondary);margin-top:3px">${escHtml(r.materialAnalysis.primarySuggestion.reasoning)}</div>
        ${r.materialAnalysis.alternatives.length > 0 ? `
          <div style="margin-top:4px;font-size:0.72rem;color:var(--text-muted)">
            Alternatives: ${r.materialAnalysis.alternatives.map(a => `${escHtml(a.name)} (${a.confidencePct}%)`).join(', ')}
          </div>` : ''}
      </div>
    </div>

    <!-- Process recommendations -->
    <div style="margin-bottom:12px">
      <div class="panel-title" style="margin-bottom:6px">Process Recommendations</div>
      ${r.processRecommendations.slice(0, 5).map(p => `
        <div class="process-rec-row">
          <div>
            <strong style="font-size:0.8rem">${escHtml(p.process)}</strong>
            <div style="font-size:0.7rem;color:var(--text-muted)">${escHtml(p.reasoning)}</div>
          </div>
          <span class="cad-confidence-badge ${p.confidencePct >= 75 ? 'High' : p.confidencePct >= 50 ? 'Medium' : 'Low'}">${p.confidencePct}%</span>
          <div class="confidence-bar-wrap">
            <div class="confidence-bar-bg">
              <div class="confidence-bar-fill" style="width:${p.confidencePct}%"></div>
            </div>
          </div>
        </div>`).join('')}
    </div>

    <!-- Manufacturability Risks -->
    ${r.manufacturabilityRisks.length > 0 ? `
    <div style="margin-bottom:12px">
      <div class="panel-title" style="margin-bottom:6px">Manufacturability Risks</div>
      ${r.manufacturabilityRisks.map(risk => `
        <div class="risk-card ${risk.severity}">
          <div class="risk-feature">${risk.severity} · ${escHtml(risk.feature)}</div>
          <div>${escHtml(risk.description)}</div>
          <div class="risk-suggestion">→ ${escHtml(risk.suggestion)}</div>
        </div>`).join('')}
    </div>` : ''}

    <!-- AI Explanation -->
    <div style="margin-bottom:12px">
      <div class="panel-title" style="margin-bottom:6px">AI Analysis</div>
      <div style="font-size:0.78rem;color:var(--text-secondary);line-height:1.55">${escHtml(r.aiExplanation)}</div>
    </div>

    ${r.costInputSuggestions.dfmIssues && r.costInputSuggestions.dfmIssues.length > 0 ? `
    <!-- DFM Issues -->
    <div style="margin-bottom:12px">
      <div class="panel-title" style="margin-bottom:6px">DFM Issues (${escHtml(commodityLabel[recommendedCommodity] ?? recommendedCommodity)} specialist)</div>
      ${r.costInputSuggestions.dfmIssues.map(issue => `
        <div class="risk-card ${issue.severity === 'Critical' ? 'High' : issue.severity}">
          <div class="risk-feature">${escHtml(issue.severity)} · ${escHtml(issue.area)}</div>
          <div>${escHtml(issue.description)}</div>
          <div style="font-size:0.72rem;color:var(--text-muted);margin-top:2px">Impact: ${escHtml(issue.impact)}</div>
          <div class="risk-suggestion">→ ${escHtml(issue.fix)}</div>
        </div>`).join('')}
    </div>` : ''}

    ${r.costInputSuggestions.costRange ? `
    <!-- Cost range -->
    <div style="margin-bottom:12px">
      <div class="panel-title" style="margin-bottom:6px">Cost Range Estimate</div>
      <div style="display:flex;gap:8px;align-items:stretch">
        <div style="flex:1;text-align:center;padding:8px 6px;background:rgba(16,185,129,0.08);border:1px solid rgba(16,185,129,0.2);border-radius:6px">
          <div style="font-size:0.66rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.03em">Optimistic</div>
          <div style="font-weight:700;font-size:0.9rem;color:var(--green)">£${r.costInputSuggestions.costRange.low.toFixed(2)}</div>
        </div>
        <div style="flex:1;text-align:center;padding:8px 6px;background:rgba(79,142,247,0.08);border:1px solid rgba(79,142,247,0.25);border-radius:6px">
          <div style="font-size:0.66rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.03em">Most Likely</div>
          <div style="font-weight:700;font-size:0.9rem;color:var(--accent)">£${r.costInputSuggestions.costRange.mid.toFixed(2)}</div>
        </div>
        <div style="flex:1;text-align:center;padding:8px 6px;background:rgba(239,68,68,0.07);border:1px solid rgba(239,68,68,0.2);border-radius:6px">
          <div style="font-size:0.66rem;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.03em">Conservative</div>
          <div style="font-weight:700;font-size:0.9rem;color:var(--red)">£${r.costInputSuggestions.costRange.high.toFixed(2)}</div>
        </div>
      </div>
    </div>` : ''}

    <!-- Suggested cost inputs + tooling amortisation -->
    ${(() => {
      const tc = cadOCCTGeometry?.toolingCostEstimates;
      let toolingCost = 0;
      let toolingLabel = '';
      const rc = recommendedCommodity;
      if (tc) {
        if (rc === 'casting' || rc === 'cast_and_machine') { toolingCost = tc.hpdcDieCostGBP; toolingLabel = 'HPDC die'; }
        else if (rc === 'injection_moulding') { toolingCost = tc.imMouldCostGBP; toolingLabel = 'IM mould'; }
        else if (rc === 'forging') { toolingCost = tc.forgeDieCostGBP; toolingLabel = 'Forge die'; }
        else if (rc === 'sheet_metal') { toolingCost = tc.progressiveDieCostGBP; toolingLabel = 'Progressive die'; }
      }
      const costRange = r.costInputSuggestions.costRange;
      const toolingPerPart = toolingCost > 0 ? toolingCost / annualVolume : 0;
      const totalMidWithTooling = costRange ? costRange.mid + toolingPerPart : null;
      return `
    <div style="margin-bottom:12px">
      <div class="panel-title" style="margin-bottom:6px">Suggested Cost Inputs <span style="font-size:0.68rem;color:var(--text-muted);font-weight:400">@ ${annualVolume.toLocaleString()} pcs/yr</span></div>
      <table class="breakdown-table" style="font-size:0.78rem">
        <tr><td>Net weight</td><td><strong>${r.costInputSuggestions.netWeightKg.toFixed(3)} kg</strong>${confBadge('netWeightKg', 'mach-net-wt', 'cast-part-wt', 'bm-wall')}</td></tr>
        <tr><td>Material</td><td>${escHtml(r.materialAnalysis.primarySuggestion.name)} (${r.costInputSuggestions.materialId})${confBadge('materialId', 'mach-mat', 'cast-mat', 'imm-mat')}</td></tr>
        <tr><td>Est. cycle time</td><td>${r.costInputSuggestions.estimatedCycleTimeHr.toFixed(4)} hr/part${confBadge('estimatedCycleTimeHr', 'mach-cycle', 'cast-hpdc-ct')}</td></tr>
        <tr><td>Setup time</td><td>${r.costInputSuggestions.estimatedSetupTimeHr.toFixed(2)} hr${confBadge('estimatedSetupTimeHr', 'mach-setup-time')}</td></tr>
        <tr><td>Operations</td><td>${r.costInputSuggestions.estimatedOperations.map(o => escHtml(o.name)).join(', ')}</td></tr>
        ${toolingCost > 0 ? `<tr><td>${escHtml(toolingLabel)} (OCCT est.)</td><td>£${toolingCost.toLocaleString('en-GB', { maximumFractionDigits: 0 })}</td></tr>
        <tr><td>Tooling/part @ ${annualVolume.toLocaleString()} pcs</td><td style="color:var(--accent)"><strong>£${toolingPerPart.toFixed(3)}</strong></td></tr>` : ''}
        ${totalMidWithTooling !== null && toolingCost > 0 ? `<tr style="border-top:1px solid var(--border)"><td><strong>Est. total/part (incl. tooling)</strong></td><td><strong style="color:var(--accent)">£${totalMidWithTooling.toFixed(2)}</strong></td></tr>` : ''}
      </table>
    </div>`;
    })()}

    <!-- Apply primary recommendation to form -->
    <div class="cad-apply-btn-row">
      <strong style="font-size:0.8rem;align-self:center">Recommended:</strong>
      <button class="btn btn-primary btn-sm" id="cad-apply-btn" data-commodity="${escHtml(recommendedCommodity)}">
        → Apply: ${escHtml(commodityLabel[recommendedCommodity] ?? recommendedCommodity)}
      </button>
      <button class="btn btn-secondary btn-sm" id="cad-apply-calc-btn" data-commodity="${escHtml(recommendedCommodity)}">
        Apply &amp; Calculate ⚡
      </button>
      <button class="btn btn-secondary btn-sm" id="cad-export-pdf-btn" style="margin-left:auto;display:flex;align-items:center;gap:4px">
        <svg viewBox="0 0 16 16" width="13" height="13" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M4 12H3a1 1 0 0 1-1-1V3a1 1 0 0 1 1-1h7l3 3v6a1 1 0 0 1-1 1h-1"/><polyline points="4 9 4 16 12 16 12 9"/><line x1="8" y1="4" x2="8" y2="12"/><polyline points="5 9 8 12 11 9"/></svg>
        Export PDF
      </button>
    </div>

    <!-- Process comparison cards (top alternative processes) -->
    ${r.processRecommendations.length > 1 ? `
    <div style="margin:10px 0 12px">
      <div class="panel-title" style="margin-bottom:6px">Alternative Processes</div>
      <div style="display:flex;flex-direction:column;gap:6px">
        ${r.processRecommendations.slice(1, 4).map(p => {
          const ct = p.commodityType as string;
          const confCls = p.confidencePct >= 75 ? 'High' : p.confidencePct >= 50 ? 'Medium' : 'Low';
          return `<div class="cad-proc-card">
            <div style="display:flex;align-items:center;gap:8px;margin-bottom:3px">
              <strong style="font-size:0.8rem;flex:1">${escHtml(commodityLabel[ct as CommodityType] ?? ct)}</strong>
              <span class="cad-confidence-badge ${confCls}" style="font-size:0.65rem">${p.confidencePct}%</span>
            </div>
            <div class="confidence-bar-bg" style="margin-bottom:5px">
              <div class="confidence-bar-fill" style="width:${p.confidencePct}%"></div>
            </div>
            <div style="font-size:0.72rem;color:var(--text-secondary);margin-bottom:6px;line-height:1.4">${escHtml(p.reasoning)}</div>
            <div style="display:flex;gap:4px">
              <button class="btn btn-secondary btn-sm cad-apply-alt-btn" data-commodity="${escHtml(ct)}" style="font-size:0.72rem">Apply</button>
              <button class="btn btn-secondary btn-sm cad-apply-alt-calc-btn" data-commodity="${escHtml(ct)}" style="font-size:0.72rem">Apply &amp; Calc ⚡</button>
            </div>
          </div>`;
        }).join('')}
      </div>
    </div>` : ''}

    <!-- Post-analysis: re-analyse with cached geometry or override & recalculate -->
    ${cadOCCTGeometry ? `
    <div style="margin-top:10px;padding:10px;border:1px solid var(--border);border-radius:6px;background:rgba(99,130,230,0.04)">
      <div class="panel-title" style="margin-bottom:8px">Re-Analyse / Adjust</div>
      <div class="field-row" style="margin-bottom:8px;gap:8px">
        <div class="field-group">
          <label style="font-size:0.72rem">Process (for re-analysis)</label>
          <select id="cad-reanalyze-commodity" style="font-size:0.8rem">
            ${CAD_COMMODITY_OPTIONS.filter(o => o.value).map(o =>
              `<option value="${o.value}"${o.value === recommendedCommodity ? ' selected' : ''}>${escHtml(o.label)}</option>`
            ).join('')}
          </select>
        </div>
        <div class="field-group">
          <label style="font-size:0.72rem">Material (override &amp; recalc)</label>
          <select id="cad-reanalyze-material" style="font-size:0.8rem">
            ${_buildCadMaterialOptions(recommendedCommodity)}
          </select>
        </div>
      </div>
      <div style="display:flex;gap:6px;flex-wrap:wrap">
        <button class="btn btn-primary btn-sm" id="cad-reanalyze-btn">↺ Re-analyse (no re-upload)</button>
        <button class="btn btn-secondary btn-sm" id="cad-override-recalc-btn">Override &amp; Recalculate ⚡</button>
      </div>
      <div id="cad-reanalyze-status" style="display:none;margin-top:6px;font-size:0.75rem;color:var(--text-muted)">Running AI analysis…</div>
    </div>` : ''}

    ${r.analysisLimitations.length > 0 ? `
    <div class="cad-limitations">
      <strong>Note:</strong> ${escHtml(r.analysisLimitations.join(' · '))}
    </div>` : ''}
  `;

  // Wire apply buttons (primary recommendation)
  el('cad-apply-btn')?.addEventListener('click', () => {
    const ct = (el('cad-apply-btn') as HTMLElement).dataset.commodity as CommodityType;
    applyCADToForm(ct, false);
  });
  el('cad-apply-calc-btn')?.addEventListener('click', () => {
    const ct = (el('cad-apply-calc-btn') as HTMLElement).dataset.commodity as CommodityType;
    applyCADToForm(ct, true);
  });

  // Wire PDF export button
  el('cad-export-pdf-btn')?.addEventListener('click', () => {
    if (cadAnalysisResult) printCADAnalysisPDF(cadAnalysisResult, currentPartPhotoDataUrl());
  });

  // Wire alternative process cards
  panel.querySelectorAll<HTMLElement>('.cad-apply-alt-btn').forEach(btn => {
    btn.addEventListener('click', () => applyCADToForm(btn.dataset.commodity as CommodityType, false));
  });
  panel.querySelectorAll<HTMLElement>('.cad-apply-alt-calc-btn').forEach(btn => {
    btn.addEventListener('click', () => applyCADToForm(btn.dataset.commodity as CommodityType, true));
  });

  // Wire re-analyse button (uses cached OCCT geometry — no re-upload)
  document.getElementById('cad-reanalyze-btn')?.addEventListener('click', () => { void reanalyzeCAD(); });

  // Wire override & recalculate button (mutates cached result's material, then applies)
  document.getElementById('cad-override-recalc-btn')?.addEventListener('click', () => {
    if (!cadAnalysisResult) return;
    const matOvr = (document.getElementById('cad-reanalyze-material') as HTMLSelectElement | null)?.value;
    if (matOvr) {
      cadAnalysisResult.costInputSuggestions.materialId = matOvr;
    }
    applyCADToForm(cadAnalysisResult.costInputSuggestions.recommendedCommodity as CommodityType, true);
  });

  // Commodity change in re-analyse section rebuilds material dropdown
  const reanalyzeCommSel = document.getElementById('cad-reanalyze-commodity') as HTMLSelectElement | null;
  const reanalyzeMatSel  = document.getElementById('cad-reanalyze-material')  as HTMLSelectElement | null;
  if (reanalyzeCommSel && reanalyzeMatSel) {
    reanalyzeCommSel.addEventListener('change', () => {
      reanalyzeMatSel.innerHTML = _buildCadMaterialOptions(reanalyzeCommSel.value);
    });
  }

  // Auto-calculate if triggered from "Analyze & Calculate" button
  if (autoCalculate) {
    applyCADToForm(recommendedCommodity, true);
  }
}

// Re-analyse using cached OCCT geometry (no STEP file re-upload required)
async function reanalyzeCAD(): Promise<void> {
  if (!cadOCCTGeometry) {
    alert('No cached OCCT geometry available. Please run a full analysis first.');
    return;
  }

  const commOvr = (document.getElementById('cad-reanalyze-commodity') as HTMLSelectElement | null)?.value ?? '';
  const matOvr  = (document.getElementById('cad-reanalyze-material')  as HTMLSelectElement | null)?.value ?? '';
  const annVol  = (document.getElementById('cad-annual-volume') as HTMLInputElement | null)?.value ?? '100000';
  const apiKey  = val('cad-api-key');

  const statusEl  = document.getElementById('cad-reanalyze-status');
  const reanalyzeBtn = document.getElementById('cad-reanalyze-btn') as HTMLButtonElement | null;

  if (statusEl) statusEl.style.display = '';
  if (reanalyzeBtn) reanalyzeBtn.setAttribute('disabled', 'true');

  try {
    const headers: HeadersInit = { 'Content-Type': 'application/json' };
    if (apiKey) headers['x-api-key'] = apiKey;

    const body: Record<string, unknown> = {
      occtGeometry: cadOCCTGeometry,
      filename: cadFile?.name ?? 'cached_part.step',
      annualVolume: annVol || '100000',
    };
    if (commOvr) body['commodity'] = commOvr;
    if (matOvr)  body['material']  = matOvr;
    if (cadPartPhotoBase64) { body['partPhotoBase64'] = cadPartPhotoBase64; body['partPhotoMime'] = cadPartPhotoMime; }

    const res = await fetch('/api/cad/reanalyze', {
      method: 'POST',
      headers,
      body: JSON.stringify(body),
    });

    const data = await res.json() as {
      success?: boolean;
      analysis?: CADAnalysisResult;
      annualVolume?: number;
      error?: string;
    };

    if (!res.ok || !data.success) throw new Error(data.error ?? `Server error ${res.status}`);

    cadAnalysisResult = data.analysis!;
    const resolvedVol = data.annualVolume ?? (parseFloat(annVol) || 100000);
    renderCADResults(cadAnalysisResult, false, resolvedVol);
  } catch (err) {
    if (statusEl) {
      statusEl.style.display = '';
      statusEl.style.color = 'var(--red)';
      statusEl.textContent = `Re-analysis error: ${err instanceof Error ? err.message : String(err)}`;
    }
  } finally {
    if (reanalyzeBtn) reanalyzeBtn.removeAttribute('disabled');
    const newStatus = document.getElementById('cad-reanalyze-status');
    if (newStatus && newStatus.textContent === 'Running AI analysis…') newStatus.style.display = 'none';
  }
}

