function collectCastAndMachineInput(): UniversalStackInput {
  const subtype = validSel<CastingSubtype>('cam-cast-subtype', ['hpdc', 'sand', 'gravity', 'investment'], 'hpdc');

  const camOps: MachiningOperation[] = Array.from(
    document.querySelectorAll<HTMLElement>('#cam-mach-ops-container .op-card')
  ).map(card => {
    const id = card.dataset.opId!;
    return {
      name: (el<HTMLInputElement>(`${id}-name`))?.value ?? '',
      type: validSel<MachiningOperation['type']>(`${id}-type`, ['turning','milling_3ax','milling_5ax','drilling','grinding','tapping','boring'], 'milling_3ax'),
      machineId: sel(`${id}-mach`),
      labourId: sel(`${id}-lab`),
      cycleTimeHr: parseFloat((el<HTMLInputElement>(`${id}-ct`))?.value) || 0,
      partsPerCycle: parseInt((el<HTMLInputElement>(`${id}-ppc`))?.value) || 1,
      oee: parseFloat((el<HTMLInputElement>(`${id}-oee`))?.value) || 0.85,
      manning: parseFloat((el<HTMLInputElement>(`${id}-manning`))?.value) || 1,
      labourTimeHr: parseFloat((el<HTMLInputElement>(`${id}-lt`))?.value) || 0,
      labourEfficiency: parseFloat((el<HTMLInputElement>(`${id}-le`))?.value) || 0.92,
    };
  });

  let subtypeExtra: Partial<CastAndMachineInputs> = {};
  if (subtype === 'hpdc') {
    subtypeExtra = { hpdc: { machineId: sel('cam-hpdc-mach'), cycleTimeSec: num('cam-hpdc-ct'), cavities: num('cam-hpdc-cav') || 1, dieCost: num('cam-hpdc-die-cost'), dieLife: num('cam-hpdc-die-life') } };
  } else if (subtype === 'sand') {
    subtypeExtra = { sand: { mouldLineId: sel('cam-sand-line'), cycleTimeHr: num('cam-sand-ct'), patternCost: num('cam-sand-pat-cost'), patternLife: num('cam-sand-pat-life'), coreCostPerPart: num('cam-sand-core') } };
  } else if (subtype === 'gravity') {
    subtypeExtra = { gravity: { machineId: sel('cam-grav-mach'), cycleTimeHr: num('cam-grav-ct'), mouldCost: num('cam-grav-mould-cost'), mouldLife: num('cam-grav-mould-life') } };
  } else if (subtype === 'investment') {
    subtypeExtra = { investment: { pourMachineId: sel('cam-inv-mach'), pourLabourId: sel('cam-inv-lab') || sel('cam-cast-lab'), pourCycleHr: num('cam-inv-ct'), waxCostPerPart: num('cam-inv-wax'), shellBuildCostPerPart: num('cam-inv-shell'), waxDieCost: num('cam-inv-wax-die') } };
  }

  const inputs: CastAndMachineInputs = {
    castingSubtype: subtype,
    materialId: sel('cam-mat'),
    castPartWeightKg: num('cam-cast-wt'),
    finishedWeightKg: num('cam-finish-wt'),
    castingYield: num('cam-cast-yield'),
    rejectRate: num('cam-reject'),
    castingLabourId: sel('cam-cast-lab'),
    castingOee: num('cam-cast-oee'),
    castingManning: num('cam-cast-manning'),
    castingLabourEfficiency: num('cam-cast-lab-eff'),
    geometryComplexity: (num('cam-complexity') || 2) as 1 | 2 | 3 | 4 | 5,
    machiningOps: camOps,
    machiningSetup: {
      setupTimeHr: num('cam-mach-setup-time'),
      batchSize: num('cam-mach-batch-size') || 50,
      machineId: sel('cam-mach-setup-mach'),
      labourId: sel('cam-mach-setup-lab'),
    },
    machiningToolingCost: num('cam-mach-tooling'),
    machiningProgrammingNRE: num('cam-mach-prog-nre'),
    amortizationVolume: num('cam-amort') || 1,
    // Post-casting secondary operations
    heatTreatmentCostPerKg: num('cam-ht-cost') || undefined,
    shotBlastCostPerPart: num('cam-shot-blast') || undefined,
    impregnationCostPerPart: num('cam-impreg') || undefined,
    deburringCostPerPart: num('cam-fettle') || undefined,
    ...subtypeExtra,
  };

  const drivers = computeCastAndMachineDrivers(inputs);
  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

/** Map a rate-library material to a laser feed-rate family (steel/stainless/aluminium). */
function inferFabMaterialFamily(materialId: string): FabMaterialFamily {
  const cat = (library.materials.find(m => m.id === materialId)?.category ?? '').toLowerCase();
  if (/alumin/.test(cat)) return 'aluminium';
  if (/stainless/.test(cat)) return 'stainless';
  return 'mild_steel';
}

function collectSheetMetalFabInput(): UniversalStackInput {
  const swCount = num('smf-sw-count');
  const swMach = sel('smf-sw-mach') || undefined;
  const swLab = sel('smf-sw-lab') || undefined;
  const migLen = num('smf-mig-len');
  const migMach = sel('smf-mig-mach') || undefined;
  const migLab = sel('smf-mig-lab') || undefined;
  const tigLen = num('smf-tig-len');
  const tigMach = sel('smf-tig-mach') || undefined;
  const tigLab = sel('smf-tig-lab') || undefined;
  const gasVal = sel('smf-gas') || undefined;

  // Guard: a weld quantity with no machine/labour is silently dropped by the
  // driver (its cost vanishes → understated quote). Warn instead of hiding it.
  _smExtraWarnings = [];
  if (swCount > 0 && (!swMach || !swLab)) _smExtraWarnings.push(`Spot welding: ${swCount} welds specified but no spot-weld machine/labour selected — weld cost omitted.`);
  if (migLen > 0 && (!migMach || !migLab)) _smExtraWarnings.push(`MIG welding: ${migLen} m specified but no MIG machine/labour selected — weld cost omitted.`);
  if (tigLen > 0 && (!tigMach || !tigLab)) _smExtraWarnings.push(`TIG welding: ${tigLen} m specified but no TIG machine/labour selected — weld cost omitted.`);
  if ((num('smf-amort') || 0) <= 0) _smExtraWarnings.push('Amortisation volume is empty/zero — tooling NRE defaulted to 1 part (full die cost on this part). Set a realistic programme volume.');

  const drivers = computeSheetMetalFabDrivers({
    materialId: sel('smf-mat'),
    partWeightKg: num('smf-part-wt'),
    materialUtilization: num('smf-mat-util') || 0.78,
    blankingMethod: validSel<FabBlankingMethod>('smf-blank-method', ['laser','plasma','waterjet','punch','shear'], 'laser'),
    blankingMachineId: sel('smf-blank-mach'),
    blankingLabourId: sel('smf-blank-lab'),
    blankingCycleTimeSec: num('smf-blank-ct'),
    assistGas: (gasVal && ['nitrogen','oxygen','air'].includes(gasVal)) ? gasVal as AssistGas : undefined,
    bendCount: num('smf-bends'),
    timePerBendSec: num('smf-bend-t') || 45,
    toolChangeCount: num('smf-tool-chg'),
    toolChangeTimeSec: num('smf-tool-chg-t') || 300,
    batchSize: num('smf-batch') || 1,
    bendMachineId: sel('smf-brake-mach'),
    bendLabourId: sel('smf-brake-lab'),
    oee: num('smf-oee'),
    manning: num('smf-manning'),
    labourEfficiency: num('smf-lab-eff'),
    rejectRate: num('smf-reject') || undefined,
    toleranceMm: num('smf-tolerance') || undefined,
    spotWeldCount: swCount > 0 ? swCount : undefined,
    spotWeldMachineId: swCount > 0 ? swMach : undefined,
    spotWeldLabourId: swCount > 0 ? swLab : undefined,
    timePerSpotWeldSec: num('smf-sw-t') || 3,
    migWeldLengthM: migLen > 0 ? migLen : undefined,
    migWeldSpeedMPerMin: num('smf-mig-spd') || 0.3,
    migWeldMachineId: migLen > 0 ? migMach : undefined,
    migWeldLabourId: migLen > 0 ? migLab : undefined,
    migWeldConsumableCostPerM: num('smf-mig-cons') || 0.40,
    tigWeldLengthM: tigLen > 0 ? tigLen : undefined,
    tigWeldSpeedMPerMin: num('smf-tig-spd') || 0.08,
    tigWeldMachineId: tigLen > 0 ? tigMach : undefined,
    tigWeldLabourId: tigLen > 0 ? tigLab : undefined,
    tigWeldConsumableCostPerM: num('smf-tig-cons') || 0.60,
    toolingCost: num('smf-tooling'),
    amortizationVolume: num('smf-amort') || 1,
  });
  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

function collectBlowMouldingInput(): UniversalStackInput {
  const deflashCt = num('bm-deflash-ct');
  const deflashMach = sel('bm-deflash-mach') || undefined;
  const deflashLab = sel('bm-deflash-lab') || undefined;
  const parisonT = num('bm-parison-t');
  const rejectR = num('bm-reject');
  const machineId = sel('bm-mach');
  const cavities = num('bm-cav') || 1;
  const partVolumeL = num('bm-part-vol');
  const mouldMaterial = validSel<BlowMouldMaterial>('bm-mould-mat', ['aluminium','steel-p20','steel-h13'], 'aluminium');
  const manualMouldCost = num('bm-mould-cost');
  const blowProcess: BlowProcess =
    machineId.startsWith('blow-ibm') ? 'ibm' :
    machineId.startsWith('blow-sbm') || machineId.includes('pet') ? 'sbm' : 'ebm';

  const drivers = computeBlowMouldingDrivers({
    materialId: sel('bm-mat'),
    partWeightKg: num('bm-part-wt'),
    flashWeightKg: num('bm-flash-wt'),
    wallThicknessMm: num('bm-wall'),
    coolTimeFactorSPerMm2: num('bm-cool-f'),
    blowTimeSec: num('bm-blow-t'),
    openCloseSec: num('bm-open-close'),
    machineId,
    labourId: sel('bm-lab'),
    cavities,
    oee: num('bm-oee'),
    manning: num('bm-manning'),
    labourEfficiency: num('bm-lab-eff'),
    mouldCost: manualMouldCost > 0 ? manualMouldCost : undefined,
    partVolumeL: partVolumeL > 0 ? partVolumeL : undefined,
    mouldMaterial,
    preformCostPerPart: num('bm-preform-cost') || undefined,
    masterbatchCostPerKg: num('bm-masterbatch') || undefined,
    mouldLife: num('bm-mould-life'),
    amortizationVolume: num('bm-amort') || 1,
    deflashMachineId: deflashCt > 0 ? deflashMach : undefined,
    deflashLabourId: deflashCt > 0 ? deflashLab : undefined,
    deflashCycleTimeSec: deflashCt > 0 ? deflashCt : undefined,
    parisonExtrusionTimeSec: parisonT > 0 ? parisonT : undefined,
    rejectRate: rejectR > 0 ? rejectR : undefined,
  });

  // Surface the mould-cost estimate when auto-derived.
  if (manualMouldCost <= 0) {
    const est = estimateBlowMouldCost({ process: blowProcess, cavities, partVolumeL: partVolumeL || 1, mouldMaterial });
    _smExtraWarnings.push(
      `Tooling: blow-mould cost auto-estimated at £${est.total.toLocaleString()} ` +
      `(${blowProcess.toUpperCase()}, ${cavities}-cav, ${partVolumeL || 1} L). Enter a Mould Cost to override.`
    );
  }

  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

/** Live advisor panel — estimated line rate, specific energy, die cost, DFM. */
function wireExtrusionAdvisor(): void {
  const out = el<HTMLDivElement>('ext-advisor');
  if (!out) return;
  const ids = ['ext-mat','ext-process','ext-kg-per-m','ext-wall','ext-screw','ext-cooling','ext-rate','ext-mach','ext-die-cost','ext-die-size','ext-die-layers','ext-die-cx','ext-minwall','ext-maxwall','ext-radius','ext-tol'];
  const update = () => {
    const family = extrusionFamilyOf(sel('ext-mat'));
    const process = (sel('ext-process') || 'profile') as ExtrusionProcess;
    const screwType = (sel('ext-mach').includes('150mm') || sel('ext-mach').includes('coex')) ? 'twin' : 'single';
    const wall = num('ext-wall') || undefined;
    const kgPerM = num('ext-kg-per-m') || undefined;
    const lr = estimateExtrusionLineRate({ screwDiameterMm: num('ext-screw') || 90, family, screwType, wallThicknessMm: wall, profileKgPerM: kgPerM, cooling: (sel('ext-cooling') || 'water-bath') as ExtrusionCooling });
    const se = estimateExtrusionSpecificEnergy(family, screwType);
    const swell = estimateDieSwellPct(family);
    const die = estimateExtrusionDieCost({ process, sizeMm: num('ext-die-size') || undefined, layers: num('ext-die-layers') || 1, complexity: (sel('ext-die-cx') || 'moderate') as DieComplexity });
    const usedRate = num('ext-rate') > 0 ? num('ext-rate') : lr.lineRateKgHr;
    const dfm = analyseExtrusionDFM({
      process, family, wallThicknessMm: wall,
      minWallMm: num('ext-minwall') || undefined, maxWallMm: num('ext-maxwall') || undefined,
      minInternalRadiusMm: num('ext-radius') || undefined, toleranceMm: num('ext-tol') || undefined, layers: num('ext-die-layers') || 1,
    });
    out.innerHTML = `
      <div style="background:#fff;border:1px solid #e0e0e0;border-radius:4px;padding:8px;margin-bottom:6px;font-size:0.82rem">
        <div style="font-weight:700;color:#ca8a04">Extrusion process estimate</div>
        <div style="margin-top:4px;display:flex;gap:14px;flex-wrap:wrap">
          <span><strong>Line rate:</strong> ${usedRate} kg/hr ${num('ext-rate') > 0 ? '(manual)' : `(auto — ${lr.limitedBy === 'cooling' ? 'cooling-limited' : 'screw-output'})`}</span>
          <span><strong>Cooling limit:</strong> ${lr.coolingLimitedKgHr != null ? lr.coolingLimitedKgHr + ' kg/hr' : 'n/a'}${lr.lineSpeedMPerMin != null ? ` (${lr.lineSpeedMPerMin} m/min)` : ''}</span>
        </div>
        <div style="margin-top:3px;display:flex;gap:14px;flex-wrap:wrap">
          <span><strong>Specific energy:</strong> ${se} kWh/kg</span>
          <span><strong>Die swell:</strong> ~${swell}%</span>
          <span><strong>Die+calibration:</strong> ${_currFmt(die.total)} (die ${_currFmt(die.die)} + calib ${_currFmt(die.calibration)}${die.layers > 0 ? ' + layers ' + _currFmt(die.layers) : ''})</span>
        </div>
      </div>
      ${renderDFMPanel(dfm.score, dfm.issues, dfm.summary)}`;
    out.style.display = 'block';
  };
  ids.forEach(id => { const e = document.getElementById(id); if (e) { e.addEventListener('change', update); e.addEventListener('input', update); } });
  update();
}

function collectExtrusionInput(): UniversalStackInput {
  const family = extrusionFamilyOf(sel('ext-mat'));
  const process = (sel('ext-process') || 'profile') as ExtrusionProcess;
  const additiveId = sel('ext-additive');
  const additivePricePerKg = additiveId ? (library.materials.find(m => m.id === additiveId)?.pricePerKg ?? 0) : 0;
  const screwType = (sel('ext-mach').includes('150mm') || sel('ext-mach').includes('coex')) ? 'twin' : 'single';

  const drivers = computeExtrusionDrivers({
    materialId: sel('ext-mat'),
    profileWeightKgPerM: num('ext-kg-per-m'),
    partLengthM: num('ext-length'),
    lineRateKgPerHr: num('ext-rate'),
    extruderId: sel('ext-mach'),
    labourId: sel('ext-lab'),
    oee: num('ext-oee'),
    manning: num('ext-manning'),
    labourEfficiency: num('ext-lab-eff'),
    startupScrapFraction: num('ext-scrap'),
    dieCost: num('ext-die-cost'),
    amortizationVolume: num('ext-amort') || 1,
    family, process, screwType,
    screwDiameterMm: num('ext-screw') || undefined,
    wallThicknessMm: num('ext-wall') || undefined,
    cooling: (sel('ext-cooling') || 'water-bath') as ExtrusionCooling,
    energyPricePerKwh: num('ext-kwh') || 0.20,
    additiveFraction: (num('ext-add-pct') || 0) / 100,
    additivePricePerKg,
    steadyScrapFraction: num('ext-steady-scrap'),
    colourChangesPerDay: num('ext-colour-chg') || 0,
    dieChangesPerDay: num('ext-die-chg') || 0,
    dieSizeMm: num('ext-die-size') || undefined,
    dieLayers: num('ext-die-layers') || 1,
    dieComplexity: (sel('ext-die-cx') || 'moderate') as DieComplexity,
    includeLeakTest: (el<HTMLInputElement>('ext-leak')?.checked) ?? false,
  });

  // Surface the auto-estimated line rate when the user left it at 0.
  if (num('ext-rate') <= 0) {
    const lr = estimateExtrusionLineRate({ screwDiameterMm: num('ext-screw') || 90, family, screwType, wallThicknessMm: num('ext-wall') || undefined, profileKgPerM: num('ext-kg-per-m') || undefined, cooling: (sel('ext-cooling') || 'water-bath') as ExtrusionCooling });
    _smExtraWarnings.push(`Line rate auto-estimated at ${lr.lineRateKgHr} kg/hr (${lr.limitedBy === 'cooling' ? 'cooling-limited by wall thickness' : 'screw-output-limited'}).`);
  }
  if (num('ext-die-cost') <= 0) _smExtraWarnings.push(`Die + calibration tooling auto-estimated at ${_currFmt(drivers.tooling.totalToolingCost)} — enter a quoted figure to override.`);

  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

function wireThermoformingAdvisor(): void {
  const out = el<HTMLDivElement>('tf-advisor');
  if (!out) return;
  const ids = ['tf-mat','tf-thk','tf-method','tf-tool-cool','tf-heat','tf-cool','tf-area','tf-mould-mat','tf-cx','tf-trim-type',
    'tf-depth','tf-open','tf-span','tf-radius','tf-draft','tf-tol','tf-plug','tf-undercut','tf-texture','tf-pps'];
  const update = () => {
    const family = thermoformFamilyOf(sel('tf-mat'));
    const method = validSel<ThermoformMethod>('tf-method', ['vacuum','pressure','twin_sheet'], 'vacuum');
    const thk = num('tf-thk') || undefined;
    const toolCool = validSel<ToolCooling>('tf-tool-cool', ['water','air','ambient'], 'water');
    const heat = num('tf-heat') > 0 ? num('tf-heat') : (thk ? estimateHeatTimeSec(family, thk) : 0);
    const cool = num('tf-cool') > 0 ? num('tf-cool') : (thk ? estimateCoolTimeSec(family, thk, toolCool) : 0);
    const se = estimateThermoformSpecificEnergy(family, method);
    const sag = thk ? estimateSagRisk(family, thk, num('tf-span') || 500) : null;
    const tool = estimateThermoformToolCost({
      projectedAreaCm2: num('tf-area') || undefined, mouldMaterial: validSel<MouldMaterial>('tf-mould-mat', ['epoxy','cast-al','cnc-al','steel'], 'cast-al'),
      method, complexity: validSel<FormComplexity>('tf-cx', ['simple','moderate','complex'], 'moderate'),
      cavities: num('tf-pps') || 1, trim: validSel('tf-trim-type', ['cnc-router','steel-rule','in-machine'] as const, 'cnc-router'),
    });
    const thinning = (num('tf-depth') && num('tf-open') && thk)
      ? estimateWallThinning({ sheetThicknessMm: thk, depthMm: num('tf-depth'), minOpeningMm: num('tf-open'), method, plugAssist: el<HTMLInputElement>('tf-plug')?.checked })
      : null;
    const dfm = analyseThermoformingDFM({
      family, method, sheetThicknessMm: thk, depthMm: num('tf-depth') || undefined, minOpeningMm: num('tf-open') || undefined,
      unsupportedSpanMm: num('tf-span') || undefined, minInternalRadiusMm: num('tf-radius') || undefined,
      draftAngleDeg: num('tf-draft') || undefined, toleranceMm: num('tf-tol') || undefined,
      hasUndercut: el<HTMLInputElement>('tf-undercut')?.checked, textured: el<HTMLInputElement>('tf-texture')?.checked,
      plugAssist: el<HTMLInputElement>('tf-plug')?.checked,
    });
    out.innerHTML = `
      <div style="background:#fff;border:1px solid #e0e0e0;border-radius:4px;padding:8px;margin-bottom:6px;font-size:0.82rem">
        <div style="font-weight:700;color:#ec4899">Thermoforming process estimate</div>
        <div style="margin-top:4px;display:flex;gap:14px;flex-wrap:wrap">
          <span><strong>Heat:</strong> ${heat ? heat + ' s' : 'n/a'}${num('tf-heat') > 0 ? ' (manual)' : ' (auto)'}</span>
          <span><strong>Cool:</strong> ${cool ? cool + ' s' : 'n/a'}${num('tf-cool') > 0 ? ' (manual)' : ' (auto)'}</span>
          <span><strong>Forming:</strong> ${formingPressureBar(method)} bar (${method})</span>
        </div>
        <div style="margin-top:3px;display:flex;gap:14px;flex-wrap:wrap">
          <span><strong>Oven energy:</strong> ${se} kWh/kg sheet</span>
          ${sag ? `<span><strong>Sag:</strong> ${sag.risk} (index ${sag.sagIndex})</span>` : ''}
          ${thinning ? `<span><strong>Draw:</strong> ${thinning.drawRatio}:1 (limit ${thinning.drawLimit}:1) → min wall ~${thinning.minWallMm.toFixed(2)} mm</span>` : ''}
        </div>
        <div style="margin-top:3px;display:flex;gap:14px;flex-wrap:wrap">
          <span><strong>Tool (est):</strong> ${_currFmt(tool.total)} (mould ${_currFmt(tool.mould)}${tool.vacuumHoles > 0 ? ' + vac ' + _currFmt(tool.vacuumHoles) : ''}${tool.trim > 0 ? ' + trim ' + _currFmt(tool.trim) : ''})</span>
          <span><strong>Tool life:</strong> ${(tool.lifeCycles / 1000).toLocaleString()}k cycles</span>
        </div>
      </div>
      ${renderDFMPanel(dfm.score, dfm.issues, dfm.summary)}`;
    out.style.display = 'block';
  };
  ids.forEach(id => { const e = document.getElementById(id); if (e) { e.addEventListener('change', update); e.addEventListener('input', update); } });
  update();
}

function collectThermoformingInput(): UniversalStackInput {
  const method = validSel<ThermoformMethod>('tf-method', ['vacuum','pressure','twin_sheet'], 'vacuum');
  const family = thermoformFamilyOf(sel('tf-mat'));
  const additiveId = sel('tf-additive');
  const additivePricePerKg = additiveId ? (library.materials.find(m => m.id === additiveId)?.pricePerKg ?? 0) : 0;

  const drivers = computeThermoformingDrivers({
    materialId: sel('tf-mat'),
    sheetWeightKg: num('tf-sheet-wt'),
    partsPerSheet: num('tf-pps') || 1,
    partWeightKg: num('tf-part-wt'),
    method,
    machineId: sel('tf-mach'),
    labourId: sel('tf-lab'),
    heatTimeSec: num('tf-heat'),
    formTimeSec: num('tf-form'),
    trimTimeSec: num('tf-trim'),
    indexTimeSec: num('tf-index'),
    oee: num('tf-oee'),
    manning: num('tf-manning'),
    labourEfficiency: num('tf-lab-eff'),
    toolCost: num('tf-tool-cost'),
    amortizationVolume: num('tf-amort') || 1,
    rejectRate: (num('tf-reject') || 0) / 100,
    family,
    sheetThicknessMm: num('tf-thk') || undefined,
    coolTimeSec: num('tf-cool') || undefined,
    toolCooling: validSel<ToolCooling>('tf-tool-cool', ['water','air','ambient'], 'water'),
    energyPricePerKwh: num('tf-kwh') || 0.20,
    additiveFraction: (num('tf-add-pct') || 0) / 100,
    additivePricePerKg,
    projectedAreaCm2: num('tf-area') || undefined,
    mouldMaterial: validSel<MouldMaterial>('tf-mould-mat', ['epoxy','cast-al','cnc-al','steel'], 'cast-al'),
    complexity: validSel<FormComplexity>('tf-cx', ['simple','moderate','complex'], 'moderate'),
    trimType: validSel('tf-trim-type', ['cnc-router','steel-rule','in-machine'] as const, 'cnc-router'),
    includeInspection: (el<HTMLInputElement>('tf-inspect')?.checked) ?? false,
  });

  // Surface auto-estimated cycle elements and tooling when left at 0.
  const thk = num('tf-thk');
  if (thk > 0 && num('tf-heat') <= 0) _smExtraWarnings.push(`Heat time auto-estimated at ${estimateHeatTimeSec(family, thk)} s (${family.toUpperCase()}, ${thk} mm).`);
  if (thk > 0 && num('tf-cool') <= 0) _smExtraWarnings.push(`Cool time auto-estimated at ${estimateCoolTimeSec(family, thk, validSel<ToolCooling>('tf-tool-cool', ['water','air','ambient'], 'water'))} s.`);
  if (num('tf-tool-cost') <= 0) _smExtraWarnings.push(`Forming + trim tooling auto-estimated at ${_currFmt(drivers.tooling.totalToolingCost)} — enter a quoted figure to override.`);
  if (thk > 0 && num('tf-depth') > 0 && num('tf-open') > 0) {
    const wt = estimateWallThinning({ sheetThicknessMm: thk, depthMm: num('tf-depth'), minOpeningMm: num('tf-open'), method, plugAssist: el<HTMLInputElement>('tf-plug')?.checked });
    if (!wt.withinLimit) _smExtraWarnings.push(`Draw ratio ${wt.drawRatio}:1 exceeds the ${wt.drawLimit}:1 limit for ${method}${el<HTMLInputElement>('tf-plug')?.checked ? ' + plug' : ''} — expect webbing / excessive thinning.`);
  }

  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

function collectRotationalMouldingInput(): UniversalStackInput {
  const heatingTimeSec = num('rm-heat');
  const coolingTimeSec = num('rm-cool');
  const manualMouldCost = num('rm-mould-cost');
  const wallThicknessMm = num('rm-wall') || 4;
  const rotoMaterial = validSel<RotoMaterialFamily>('rm-mat-fam', ['pe','xlpe','pp','pa12'], 'pe');
  const coolingMethod = validSel<RotoCoolingMethod>('rm-cool-method', ['ambient','forced-air','water-spray'], 'forced-air');
  const projectedAreaCm2 = num('rm-proj-area');
  const mouldType = validSel<RotoMouldType>('rm-mould-type', ['cast-al','cnc-al','fabricated'], 'cast-al');

  const drivers = computeRotationalMouldingDrivers({
    materialId: sel('rm-mat'),
    partWeightKg: num('rm-part-wt'),
    powderCostAdderPerKg: num('rm-powder-adder'),
    numArms: num('rm-num-arms') || 3,
    partsPerArm: num('rm-parts-per-arm') || 1,
    heatingTimeSec,
    coolingTimeSec,
    loadUnloadTimeSec: num('rm-load'),
    machineId: sel('rm-mach'),
    labourId: sel('rm-lab'),
    oee: num('rm-oee'),
    manning: num('rm-manning'),
    labourEfficiency: num('rm-lab-eff'),
    mouldCost: manualMouldCost > 0 ? manualMouldCost : 0,
    mouldLife: num('rm-mould-life'),
    amortizationVolume: num('rm-amort') || 1,
    wallThicknessMm,
    rotoMaterial,
    coolingMethod,
    projectedAreaCm2,
    mouldType,
    mouldComplexity: 'moderate',
    masterbatchCostPerKg: num('rm-masterbatch') || undefined,
  });

  // Surface predicted cycle times when auto-derived.
  if (heatingTimeSec <= 0 || coolingTimeSec <= 0) {
    const cyc = estimateRotoCycle({ wallThicknessMm, material: rotoMaterial, coolingMethod });
    _smExtraWarnings.push(
      `Cycle: heating/cooling auto-predicted at ${cyc.heatingSec}s / ${cyc.coolingSec}s ` +
      `(${wallThicknessMm} mm ${rotoMaterial}, ${coolingMethod}). Enter times to override.`
    );
  }
  if (manualMouldCost <= 0) {
    const est = estimateRotoMouldCost({ projectedAreaCm2, mouldType, complexity: 'moderate' });
    _smExtraWarnings.push(
      `Tooling: roto mould cost auto-estimated at £${est.total.toLocaleString()} ` +
      `(${mouldType}, ${projectedAreaCm2} cm²). Enter a Mould Cost to override.`
    );
  }

  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

// ─── Blow / Roto DFM advisor panels (BR3/BR4) ─────────────────────────────────

interface _DFMIssueLike { severity: string; title: string; description: string; recommendation: string }
function renderDFMPanel(score: number, issues: _DFMIssueLike[], summary: string): string {
  const sevColor: Record<string, string> = { critical: '#c62828', major: '#e65100', minor: '#f9a825', opportunity: '#2e7d32' };
  const scoreColor = score >= 8 ? '#2e7d32' : score >= 5 ? '#e65100' : '#c62828';
  const body = issues.length === 0
    ? `<div style="color:#2e7d32;margin-top:4px">✓ ${escHtml(summary)}</div>`
    : issues.map(i => `
        <div style="margin-top:4px;padding-left:6px;border-left:3px solid ${sevColor[i.severity] ?? '#999'}">
          <div style="font-weight:600;color:${sevColor[i.severity] ?? '#555'}">[${i.severity.toUpperCase()}] ${escHtml(i.title)}</div>
          <div style="color:#555">${escHtml(i.description)}</div>
          <div style="color:#333"><em>Fix:</em> ${escHtml(i.recommendation)}</div>
        </div>`).join('');
  return `<div style="background:#fff;border:1px solid #e0e0e0;border-radius:4px;padding:8px">
      <span style="font-weight:700">DFM score: <span style="color:${scoreColor}">${score}/10</span></span>${body}
    </div>`;
}

function wireBlowDFM(): void {
  const btn = document.getElementById('bm-dfm-btn');
  if (!btn) return;
  btn.addEventListener('click', () => {
    const machineId = sel('bm-mach');
    const process: BlowProcess = machineId.startsWith('blow-ibm') ? 'ibm'
      : machineId.startsWith('blow-sbm') || machineId.includes('pet') ? 'sbm' : 'ebm';
    const r = analyseBlowDFM({
      process,
      wallThicknessMm: num('bm-wall'),
      blowUpRatio: num('bm-dfm-bur') || undefined,
      parisonLtoD: num('bm-dfm-ld') || undefined,
      minCornerRadiusMm: num('bm-dfm-corner') || undefined,
      handleOrWeldLine: sel('bm-dfm-weld') === 'yes',
      toleranceMm: num('bm-dfm-tol') || undefined,
    });
    const out = document.getElementById('bm-dfm-result');
    if (out) { out.innerHTML = renderDFMPanel(r.score, r.issues, r.summary); out.style.display = 'block'; }
  });
}

function wireRotoDFM(): void {
  const btn = document.getElementById('rm-dfm-btn');
  if (!btn) return;
  btn.addEventListener('click', () => {
    const r = analyseRotoDFM({
      wallThicknessMm: num('rm-wall'),
      material: validSel<RotoMaterialFamily>('rm-mat-fam', ['pe','xlpe','pp','pa12'], 'pe'),
      minInternalRadiusMm: num('rm-dfm-radius') || undefined,
      draftAngleDeg: num('rm-dfm-draft'),
      flatUnsupportedSpanMm: num('rm-dfm-span') || undefined,
      enclosedNoVent: sel('rm-dfm-vent') === 'yes',
      doubleWallKissOff: sel('rm-dfm-kiss') === 'yes',
    });
    const out = document.getElementById('rm-dfm-result');
    if (out) { out.innerHTML = renderDFMPanel(r.score, r.issues, r.summary); out.style.display = 'block'; }
  });
}

function collectRubberInput(): UniversalStackInput {
  const materialId = sel('rub-mat');
  const process = (sel('rub-process') || 'compression_mould') as RubberProcess;
  const manualCycleSec = num('rub-cycle-sec');
  const manualMouldCost = num('rub-mould-cost');
  const thicknessMm = num('rub-thickness') || 3;
  const compoundFamily = rubberCompoundFamilyFor(materialId);
  const moldTempC = num('rub-mold-temp') || undefined;
  const projectedAreaCm2 = num('rub-proj-area') || undefined;
  const moldSteel = validSel<RubberMouldSteel>('rub-mold-steel', ['aluminium','p20','h13'], 'p20');
  const mouldComplexity = validSel<RubberComplexity>('rub-mold-cplx', ['simple','moderate','complex'], 'moderate');
  const deflashSec = num('rub-deflash-sec');

  const drivers = computeRubberDrivers({
    materialId,
    partWeightKg: num('rub-part-wt') || 0.05,
    flashAndRunnerWeightKg: num('rub-flash-wt'),
    process,
    machineId: sel('rub-mach'),
    labourId: sel('rub-lab'),
    // 0 → predict cure cycle from thickness × compound × temp.
    cycleTimeSec: manualCycleSec > 0 ? manualCycleSec : 0,
    thicknessMm,
    compoundFamily,
    moldTempC,
    cavities: num('rub-cavities') || 4,
    oee: num('rub-oee') || 0.80,
    manning: num('rub-manning') || 1,
    labourEfficiency: num('rub-lab-eff') || 0.90,
    rejectRate: num('rub-reject') || 0,
    cureTimeSec: num('rub-cure-sec') || undefined,
    cureOvenMachineId: sel('rub-cure-mach') || undefined,
    // 0 → estimate mould cost parametrically.
    mouldCost: manualMouldCost > 0 ? manualMouldCost : 0,
    projectedAreaCm2,
    moldSteel,
    mouldComplexity,
    metalInserts: num('rub-inserts') || undefined,
    mouldLife: num('rub-mould-life') || 200000,
    amortizationVolume: num('rub-amort') || 50000,
    bondingPrimerCostPerPart: num('rub-primer') || undefined,
    inspectionCostPerPart: num('rub-inspect') || undefined,
    deflashMachineId: deflashSec > 0 ? (sel('rub-deflash-mach') || undefined) : undefined,
    deflashLabourId: deflashSec > 0 ? (sel('rub-deflash-lab') || undefined) : undefined,
    deflashCycleSec: deflashSec > 0 ? deflashSec : undefined,
  });

  if (manualCycleSec <= 0) {
    _smExtraWarnings.push(
      `Cure cycle auto-predicted (${compoundFamily}, ${thicknessMm} mm${moldTempC ? `, ${moldTempC}°C` : ''}). Enter Cycle Time to override.`
    );
  }
  if (manualMouldCost <= 0) {
    const est = estimateRubberMouldCost({ process, cavities: num('rub-cavities') || 4, projectedAreaCm2, moldSteel, complexity: mouldComplexity, metalInserts: num('rub-inserts') || undefined });
    _smExtraWarnings.push(`Tooling: rubber mould auto-estimated at £${est.total.toLocaleString()} (${process.replace(/_/g,' ')}, ${num('rub-cavities') || 4}-cav). Enter a Mould Cost to override.`);
  }

  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

/** Infer the rubber compound family from a material id (for cure prediction). */
function rubberCompoundFamilyFor(materialId: string): RubberCompoundFamily {
  const id = materialId.toLowerCase();
  if (id.includes('ffkm')) return 'ffkm';
  if (id.includes('fkm') || id.includes('viton') || id.includes('fvmq')) return 'fkm';
  if (id.includes('hnbr')) return 'hnbr';
  if (id.includes('nbr')) return 'nbr';
  if (id.includes('bromobutyl') || id.includes('chlorobutyl') || id.includes('halobutyl')) return 'halobutyl';
  if (id.includes('iir') || id.includes('butyl')) return 'iir';
  if (id.includes('epdm-peroxide')) return 'epdm-peroxide';
  if (id.includes('epdm')) return 'epdm-sulphur';
  if (id.includes('lsr') || id.includes('silicone-medical')) return 'silicone-lsr';
  if (id.includes('silicone') || id.includes('vmq')) return 'silicone-hcr';
  if (id.includes('acm')) return 'acm';
  if (id.includes('aem')) return 'aem';
  if (id.includes('eco')) return 'eco';
  if (id.includes('csm')) return 'csm';
  if (id.includes('cr')) return 'cr';
  if (id.includes('sbr')) return 'sbr';
  if (id.includes('-br') || id === 'mat-br') return 'br';
  if (id.includes('pu-elastomer')) return 'pu';
  return 'nr';
}

/** Wire the rubber DFM advisor panel. */
function wireRubberDFM(): void {
  const btn = document.getElementById('rub-dfm-btn');
  if (!btn) return;
  btn.addEventListener('click', () => {
    const r = analyseRubberDFM({
      compoundFamily: rubberCompoundFamilyFor(sel('rub-mat')),
      thicknessMm: num('rub-thickness') || 3,
      minWallMm: num('rub-dfm-minwall') || undefined,
      maxWallMm: num('rub-dfm-maxwall') || undefined,
      draftAngleDeg: num('rub-dfm-draft'),
      flashLineOnSealingFace: sel('rub-dfm-flash') === 'yes',
      undercutCount: num('rub-dfm-undercut') || undefined,
      metalInsert: (num('rub-inserts') || 0) > 0,
      toleranceMm: num('rub-dfm-tol') || undefined,
    });
    const out = document.getElementById('rub-dfm-result');
    if (out) { out.innerHTML = renderDFMPanel(r.score, r.issues, r.summary); out.style.display = 'block'; }
  });
}

function collectCompositesInput(): UniversalStackInput {
  const drivers = computeCompositeDrivers({
    fibrePricePerKg: num('comp-fibre-price') || 32.00,
    resinPricePerKg: num('comp-resin-price') || 0,
    fibreWeightFraction: num('comp-fibre-frac') || 0.60,
    partWeightKg: num('comp-part-wt') || 1.80,
    wasteFraction: num('comp-waste-frac') || 0.20,
    process: (sel('comp-process') || 'prepreg_layup') as CompositeProcess,
    areaM2: num('comp-area') || 0.65,
    plies: num('comp-plies') || 8,
    layupLabourId: sel('comp-layup-lab'),
    layupTimeHrPerPart: num('comp-layup-time') || 3.50,
    oee: num('comp-oee') || 0.78,
    manning: num('comp-manning') || 2,
    labourEfficiency: num('comp-lab-eff') || 0.90,
    cureMachineId: sel('comp-cure-mach'),
    cureLabourId: sel('comp-cure-lab'),
    cureTimeHr: num('comp-cure-time') || 4.00,
    partsPerCureCycle: num('comp-cure-batch') || 4,
    trimMachineId: sel('comp-trim-mach') || undefined,
    trimLabourId: sel('comp-trim-lab'),
    trimTimeHr: num('comp-trim-time') || 0.50,
    ndiCostPerPart: num('comp-ndi') || undefined,
    rejectRate: num('comp-reject') || 0.04,
    toolingCost: num('comp-tool-cost') || 18000,
    toolingLife: num('comp-tool-life') || 400,
    amortizationVolume: num('comp-amort') || 2000,
  });
  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

function collectWiringHarnessInput(): UniversalStackInput {
  const wireRows = Array.from(document.querySelectorAll('.wire-row'));
  const wires = wireRows
    .map(row => ({
      crossSectionMm2: parseFloat((row.querySelector('.wire-gauge') as HTMLInputElement)?.value || '0.5'),
      lengthM: parseFloat((row.querySelector('.wire-length') as HTMLInputElement)?.value || '0'),
      pricePerM: parseFloat((row.querySelector('.wire-price') as HTMLInputElement)?.value || '0'),
    }))
    .filter(w => w.lengthM > 0);

  const connRows = Array.from(document.querySelectorAll('.conn-row'));
  const connectors = connRows
    .map(row => ({
      count: parseInt((row.querySelector('.conn-count') as HTMLInputElement)?.value || '0', 10),
      costEach: parseFloat((row.querySelector('.conn-cost') as HTMLInputElement)?.value || '0'),
      circuitsPerConnector: parseInt((row.querySelector('.conn-circuits') as HTMLInputElement)?.value || '1', 10),
      terminationTimeSec: parseFloat((row.querySelector('.conn-term-time') as HTMLInputElement)?.value || '10'),
    }))
    .filter(c => c.count > 0);

  const drivers = computeWiringHarnessDrivers({
    wires,
    connectors,
    spliceCount: num('harn-splices') || 0,
    spliceCostEach: num('harn-splice-cost') || 0.08,
    conduitLengthM: num('harn-conduit-len') || 0,
    conduitCostPerM: num('harn-conduit-price') || 0.35,
    tapeMetres: num('harn-tape-m') || 0,
    tapeCostPerM: num('harn-tape-price') || 0.12,
    labourId: sel('harn-asm-lab'),
    assemblyTimeHr: num('harn-asm-time') || 0.45,
    oee: num('harn-oee') || 0.85,
    manning: num('harn-manning') || 1,
    labourEfficiency: num('harn-lab-eff') || 0.90,
    testMachineId: sel('harn-test-mach') || undefined,
    testLabourId: sel('harn-test-lab'),
    testTimeHr: num('harn-test-time') || 0.05,
    rejectRate: num('harn-reject') || 0.02,
    boardingBoardCost: num('harn-board-cost') || 800,
    boardingBoardLife: num('harn-board-life') || 20000,
    amortizationVolume: num('harn-amort') || 10000,
  });
  return { ...getUniversalTail(), rawMaterial: drivers.rawMaterial, operations: drivers.operations, tooling: drivers.tooling };
}

function collectInput(): UniversalStackInput {
  switch (activeCommodity) {
    case 'machining':            return collectMachiningInput();
    case 'sheet_metal':          return collectSheetMetalInput();
    case 'sheet_metal_fab':      return collectSheetMetalFabInput();
    case 'injection_moulding':   return collectIMMInput();
    case 'blow_moulding':        return collectBlowMouldingInput();
    case 'extrusion':            return collectExtrusionInput();
    case 'thermoforming':        return collectThermoformingInput();
    case 'rotational_moulding':  return collectRotationalMouldingInput();
    case 'casting':              return collectCastingInput();
    case 'forging':              return collectForgingInput();
    case 'painting':             return collectPaintingInput();
    case 'biw_assembly':         return collectBIWInput();
    case 'pcb_fab':              return collectPCBFabInput();
    case 'pcba':                 return collectPCBAInput();
    case 'cast_and_machine':     return collectCastAndMachineInput();
    case 'rubber':               return collectRubberInput();
    case 'composites':           return collectCompositesInput();
    case 'wiring_harness':       return collectWiringHarnessInput();
    case 'automotive_software':
      throw new Error('Use the Calculate button inside the Automotive Software Should-Cost panel.');
    case 'cad_analysis':
      throw new Error('Apply CAD analysis results to a commodity form first using the "Apply to cost engine" button, then calculate.');
    case 'ai_agent' as CommodityType:
      throw new Error('Use the AI Agent chat to build and compute your cost estimate.');
    case 'assembly':
      throw new Error('Use the Calculate Assembly button for Assembly BOM mode.');
    default:
      throw new Error(`Unknown commodity: ${activeCommodity}`);
  }
}

// ─── Compute ──────────────────────────────────────────────────────────────────

function compute(): void {
  const errBox = el('validation-errors');
  const warnBox = el('validation-warnings');
  const calcBtn = el<HTMLButtonElement>('calc-btn');
  const originalLabel = calcBtn.textContent ?? 'Calculate';
  calcBtn.disabled = true;
  calcBtn.textContent = '⏳ Calculating…';

  _smExtraWarnings = [];
  let input: UniversalStackInput;
  try {
    input = collectInput();
  } catch (err) {
    calcBtn.disabled = false;
    calcBtn.textContent = originalLabel;
    errBox.style.display = 'block';
    errBox.innerHTML = `<strong>Input error:</strong> ${escHtml(err instanceof Error ? err.message : String(err))}`;
    return;
  }

  const validation = validateStackInput(input, library);

  if (!validation.valid) {
    calcBtn.disabled = false;
    calcBtn.textContent = originalLabel;
    errBox.style.display = 'block';
    errBox.innerHTML = `<strong>Errors:</strong><ul>${validation.errors.map(e => `<li>${escHtml(e.field)}: ${escHtml(e.message)}</li>`).join('')}</ul>`;
    warnBox.style.display = 'none';
    return;
  }
  errBox.style.display = 'none';

  const allWarnings = [
    ...validation.warnings.map(w => `${w.field}: ${w.message}`),
    ..._smExtraWarnings,
  ];
  if (allWarnings.length > 0) {
    warnBox.style.display = 'block';
    warnBox.innerHTML = `<strong>Warnings:</strong><ul>${allWarnings.map(w => `<li>${escHtml(w)}</li>`).join('')}</ul>`;
  } else {
    warnBox.style.display = 'none';
  }

  try {
    lastLCResult = null;

    // Inject learning curve config into the formal input (wires through computeUniversalStack)
    const lcEnabled = (document.getElementById('lc-enabled') as HTMLInputElement)?.checked;
    if (lcEnabled) {
      const annualVolume = parseFloat((document.getElementById('annual-volume') as HTMLInputElement)?.value) || 10000;
      const referenceVolume = parseFloat((document.getElementById('reference-volume') as HTMLInputElement)?.value) || 1000;
      const curvePct = parseFloat((document.getElementById('learning-curve-pct') as HTMLInputElement)?.value) || 85;
      input = { ...input, annualVolume, learningCurve: { enabled: true, curvePct, referenceVolume } };
    }

    const result = computeUniversalStack(input, library);

    // Populate lastLCResult from formal result for display compatibility
    if (result.learningCurveApplied) {
      lastLCResult = {
        baseLabourCost: result.breakdown.labour - result.learningCurveApplied.labourSaving,
        adjustedLabourCost: result.breakdown.labour,
        adjustmentFactor: result.learningCurveApplied.adjustmentFactor,
        volumeEffect: result.learningCurveApplied.labourSaving,
        params: {
          annualVolume: result.learningCurveApplied.annualVolume,
          referenceVolume: result.learningCurveApplied.referenceVolume,
          curvePct: result.learningCurveApplied.curvePct,
        },
      };
    }

    lastResult = result;
    lastInput = input;
    pushCostingRecord({ totalCost: result.total, confidence: result.warnings?.length ? 'Medium' : 'High', breakdown: result.breakdown, warnings: result.warnings });
    showResultsArea();
    renderBreakdown(result);
    updateTabBadges(result, input);
    fetchAICommentary(result);

    // Show action buttons
    el('export-excel-btn').style.display = '';
    el('export-pdf-btn').style.display = '';
    el('export-card-btn').style.display = '';
    el('export-all-pdf-btn').style.display = '';
    el('save-scenario-btn').style.display = '';
  } catch (err) {
    errBox.style.display = 'block';
    errBox.innerHTML = `<strong>Calculation error:</strong> ${escHtml(err instanceof Error ? err.message : String(err))}`;
  } finally {
    calcBtn.disabled = false;
    calcBtn.textContent = originalLabel;
  }
}

// ─── Results area ─────────────────────────────────────────────────────────────

function showResultsArea(): void {
  const resultsEl = el('results-tabs');
  // Explicit flex (not '') so no stale inline style can leave it collapsed, and
  // force it above sibling content — guards the "empty tab strip" regression.
  resultsEl.style.display = 'flex';
  resultsEl.style.visibility = 'visible';
  switchResultTab('breakdown');
  // Make sure the tab bar is actually in view (its scroll container may have been
  // left scrolled past the top by a previous render / demo switch).
  (resultsEl.closest('.results-panel') as HTMLElement | null)?.scrollTo?.({ top: 0 });
  // Animate results panel after Chart.js renders (needs one frame)
  setTimeout(() => {
    onResultsReady();
    motionRevealRows('#results-tabs .breakdown-row, #results-tabs tr');
  }, 80);
  // Failsafe: whatever the reveal animation does, guarantee the tab bar is
  // visible shortly after (a stranded autoAlpha/opacity tween must never leave
  // an empty tab strip). Runs after the ~0.3s reveal completes.
  setTimeout(() => {
    const bar = document.getElementById('results-tabs');
    if (bar) { bar.style.visibility = 'visible'; bar.style.opacity = '1'; bar.style.display = 'flex'; }
    document.querySelectorAll<HTMLElement>('.rtab').forEach(t => {
      t.style.visibility = 'visible'; t.style.opacity = '1';
    });
  }, 500);
}

// ─── Upload / Parts Library Tab ───────────────────────────────────────────────
